      <span id="reaction-feed-value">.054</span>
    </label>
    <label class="control-label">
      kill
      <input id="reaction-kill" type="range" min="35" max="75" value="62" />
      <span id="reaction-kill-value">.062</span>
    </label>
    <label class="control-label">
      brush
      <input id="reaction-brush" type="range" min="2" max="18" value="7" />
    </label>
    <button class="toolbar-button" id="reaction-pause" type="button">pause</button>
    <button class="toolbar-button" id="reaction-seed" type="button">seed</button>
    <button class="toolbar-button" id="reaction-clear" type="button">clear</button>
    <span class="reaction-help">paint chemistry · Gray-Scott u/v fields</span>
  </Fragment>

  <div id="reaction-readout" aria-live="polite">
    <span id="reaction-status">running</span>
    <span id="reaction-stats">0 steps</span>
  </div>

  <div class="canvas-stage" id="reaction-stage">
    <canvas id="reaction-canvas"></canvas>
  </div>
