  #reaction-feed-value,
  #reaction-kill-value {
    min-width: 3rem;
    color: var(--muted);
    font-variant-numeric: tabular-nums;
  }

  .reaction-help {
    margin-left: auto;
    color: var(--muted);
    font-size: .78rem;
  }

  #reaction-readout {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    padding: .35rem var(--space);
    border-bottom: 1px solid var(--line);
    color: var(--muted);
    font-size: .78rem;
    font-variant-numeric: tabular-nums;
  }

  #reaction-status { color: var(--fg); }

  #reaction-stage {
    cursor: crosshair;
    touch-action: none;
  }

  #reaction-canvas {
    display: block;
    width: 100%;
    height: 100%;
    image-rendering: pixelated;
  }
</style>

<script>
  import '../scripts/reaction-diffusion.ts';
</script>

